// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PauseModule {
    bool public isPaused;

    event Paused();
    event Unpaused();

    function pause() external {
        require(!isPaused, "Already paused");
        isPaused = true;
        emit Paused();
    }

    function unpause() external {
        require(isPaused, "Not paused");
        isPaused = false;
        emit Unpaused();
    }
}

